#include <stdio.h>
#include <stdlib.h>

// Function to find the next higher peak for each element in heights
int* next_higher_peak(int* heights, int n) {

    int* result = (int*)malloc(n * sizeof(int));
    int* stack = (int*)malloc(n * sizeof(int));
    int top = -1;  // Initialize stack top

    // Initialize result array with -1
    for (int i = 0; i < n; ++i) {
        result[i] = -1;
    }

    // Traverse through each element in heights
    for (int i = 0; i < n; ++i) {
        // Pop elements from stack while stack is not empty and current element is greater than the element at stack top
        while (top != -1 && heights[i] > heights[stack[top]]) {
            int idx = stack[top--];
            result[idx] = heights[i];
        }
        // Push current element index to stack
        stack[++top] = i;
    }

    // Free allocated memory for stack
    free(stack);

    return result;
}

int main() {
    int n;
    // Take the size of the heights array as input
    scanf("%d", &n);

    int* heights = (int*)malloc(n * sizeof(int));

    // Take the heights array elements as input
    for (int i = 0; i < n; ++i) {
        scanf("%d", &heights[i]);
    }

    // Get the next higher peaks
    int* result = next_higher_peak(heights, n);

    // Print the result
    for (int i = 0; i < n; ++i) {
        printf("%d ", result[i]);
    }

    // Free allocated memory for heights and result arrays
    free(heights);
    free(result);

    return 0;
}

